/*
 * AWS IoT Device - Main Application
 * FSM-based architecture for scalability
 *
 * Boot Mode Logic:
 * 1. RECOVERY MODE: If RTC recovery flag is set (from previous connection
 * failure in headless mode)
 *    - Initialize LCD FIRST (before WiFi fragments PSRAM)
 *    - Display error message on LCD
 *    - Start captive portal for configuration
 *
 * 2. HEADLESS MODE: If headless setting is enabled in NVS (and not in recovery)
 *    - Skip LCD initialization entirely (saves PSRAM and power)
 *    - Start connectivity watchdog to monitor connection
 *    - If connection fails, trigger recovery reboot
 *
 * 3. NORMAL MODE: Default operation with LCD
 *    - Initialize LCD FIRST (before WiFi)
 *    - Normal operation with display feedback
 */

#include "driver/gpio.h"
#include "esp_app_desc.h"
#include "esp_log.h"
#include "esp_system.h"
#include "freertos/FreeRTOS.h"
#include "freertos/task.h"
#include "nvs_flash.h"
#include <stdio.h>

#include "aws_iot_task.h"
#include "battery_task.h"
#include "cloud_log.h"
#include "fsm.h"
#include "lcd_task.h"
#include "model_task.h"
#include "power_manager.h"
#include "psram_diagnostics.h"
#include "recovery_watchdog.h"
#include "system_info.h"
#include "system_task.h"
#include "wifi_task.h"

static const char *TAG = "main";

/* Boot mode enumeration */
typedef enum {
  BOOT_MODE_NORMAL,    /* LCD on, normal operation */
  BOOT_MODE_HEADLESS,  /* LCD off, watchdog active */
  BOOT_MODE_RECOVERY,  /* LCD on, showing error, captive portal */
  BOOT_MODE_TIMER_WAKE /* Woke from timer - quick telemetry then sleep */
} boot_mode_t;

static boot_mode_t s_boot_mode = BOOT_MODE_NORMAL;

extern "C" void app_main(void) {
  /* Initialize NVS */
  esp_err_t ret = nvs_flash_init();
  if (ret == ESP_ERR_NVS_NO_FREE_PAGES ||
      ret == ESP_ERR_NVS_NEW_VERSION_FOUND) {
    ESP_ERROR_CHECK_WITHOUT_ABORT(nvs_flash_erase());
    ret = nvs_flash_init();
  }
  ESP_ERROR_CHECK_WITHOUT_ABORT(ret);

  /* Reduce log levels for non-critical components to minimize LCD interference
   */
  esp_log_level_set("wifi", ESP_LOG_INFO);
  esp_log_level_set("esp_netif_handlers", ESP_LOG_INFO);
  esp_log_level_set("wifi_prov", ESP_LOG_INFO);
  esp_log_level_set("protocomm_nimble", ESP_LOG_INFO);
  esp_log_level_set("mesh", ESP_LOG_INFO);
  esp_log_level_set("system_api", ESP_LOG_INFO);

  /* Initialize cloud log publisher — captures ESP_LOG output into a
   * ring buffer for batch MQTT publishing to device/{id}/logs.
   * Level is configured via menuconfig / sdkconfig.defaults. */
#ifdef CONFIG_CLOUD_LOG_ENABLE
#if defined(CONFIG_CLOUD_LOG_LEVEL_ERROR)
  cloud_log_init(ESP_LOG_ERROR);
#elif defined(CONFIG_CLOUD_LOG_LEVEL_WARN)
  cloud_log_init(ESP_LOG_WARN);
#elif defined(CONFIG_CLOUD_LOG_LEVEL_DEBUG)
  cloud_log_init(ESP_LOG_DEBUG);
#else
  cloud_log_init(ESP_LOG_INFO);
#endif
#endif

  /* ========================================================================
   * DEEP SLEEP WAKE DETECTION
   * ========================================================================
   * Check wake cause EARLY to determine boot path.
   */
  power_manager_init();
  esp_sleep_wakeup_cause_t wake_cause = power_manager_get_wakeup_cause();

  if (power_manager_woke_from_timer()) {
    ESP_LOGI(TAG, "========================================");
    ESP_LOGI(TAG, "⏰ WAKE FROM TIMER (12h telemetry)");
    ESP_LOGI(TAG, "========================================");
    s_boot_mode = BOOT_MODE_TIMER_WAKE;
  } else if (power_manager_woke_from_pir()) {
    ESP_LOGI(TAG, "========================================");
    ESP_LOGI(TAG, "🚿 WAKE FROM PIR (motion detected)");
    ESP_LOGI(TAG, "========================================");
    /* Proceed with normal boot - will detect shower */
    s_boot_mode = BOOT_MODE_NORMAL;
  } else {
    ESP_LOGI(TAG, "========================================");
    ESP_LOGI(TAG, "🔌 NORMAL BOOT (%s)", power_manager_get_wakeup_cause_str());
    ESP_LOGI(TAG, "========================================");
  }

  ESP_LOGI(TAG, "========================================");
  ESP_LOGI(TAG, "AWS IoT Device - FSM Architecture");
  ESP_LOGI(TAG, "📦 Firmware: %s", esp_app_get_description()->version);
  ESP_LOGI(TAG, "========================================");

  /* Print system information */
  system_info_print();

  /* Run PSRAM diagnostics - combines detection and bandwidth testing */
  psram_run_diagnostics(true); /* verbose=true for detailed output */

  /* ========================================================================
   * RECOVERY WATCHDOG INITIALIZATION (MUST BE EARLY)
   * ========================================================================
   * Initialize recovery watchdog to check RTC flags and determine boot mode.
   * This MUST happen before any tasks are started.
   */
  if (recovery_watchdog_init(power_manager_woke_from_timer()) != ESP_OK) {
    ESP_LOGE(TAG, "Failed to initialize recovery watchdog");
    /* Continue anyway - default to normal mode */
  }

  /* Determine boot mode based on recovery watchdog state */
  if (recovery_watchdog_is_recovery_mode()) {
    s_boot_mode = BOOT_MODE_RECOVERY;
    ESP_LOGW(TAG, "========================================");
    ESP_LOGW(TAG, "BOOT MODE: RECOVERY");
    ESP_LOGW(TAG, "Device rebooted due to connection failure");
    ESP_LOGW(TAG, "LCD will be initialized to show error");
    ESP_LOGW(TAG, "========================================");
  } else if (recovery_watchdog_is_headless_enabled()) {
    s_boot_mode = BOOT_MODE_HEADLESS;
    ESP_LOGI(TAG, "========================================");
    ESP_LOGI(TAG, "BOOT MODE: HEADLESS");
    ESP_LOGI(TAG, "LCD disabled to save power");
    ESP_LOGI(TAG, "Watchdog will monitor connectivity");
    ESP_LOGI(TAG, "========================================");
  } else {
    s_boot_mode = BOOT_MODE_NORMAL;
    ESP_LOGI(TAG, "========================================");
    ESP_LOGI(TAG, "BOOT MODE: NORMAL");
    ESP_LOGI(TAG, "LCD enabled for normal operation");
    ESP_LOGI(TAG, "========================================");
  }

  /* Initialize Battery ADC */
  if (battery_task_init() != ESP_OK) {
    ESP_LOGW(TAG, "Failed to initialize battery ADC (non-fatal)");
  }

  /* Initialize FSM */
  if (fsm_init() != ESP_OK) {
    ESP_LOGE(TAG, "Failed to initialize FSM");
    return;
  }

  /* ========================================================================
   * LCD INITIALIZATION - CONDITIONAL BASED ON BOOT MODE
   * ========================================================================
   * CRITICAL: LCD must be started BEFORE WiFi in NORMAL and RECOVERY modes.
   * The RGB LCD driver requires a large contiguous PSRAM block for the
   * bounce buffer. Once WiFi initializes, PSRAM becomes fragmented and
   * the allocation will fail.
   *
   * In HEADLESS mode, we skip LCD entirely to save memory and power.
   */
  if (s_boot_mode == BOOT_MODE_NORMAL || s_boot_mode == BOOT_MODE_RECOVERY) {
    /* Start LCD Display Task FIRST
     * This ensures the LCD driver can allocate the necessary contiguous memory
     * (bounce buffer) before the WiFi stack fragments the heap.
     */
    if (lcd_task_start() != ESP_OK) {
      ESP_LOGE(TAG, "Failed to start LCD task");
      /* In recovery OR normal mode, if LCD fails, fall back to headless */
      ESP_LOGE(TAG,
               "LCD initialization failed - falling back to HEADLESS mode");

      if (s_boot_mode == BOOT_MODE_RECOVERY) {
        recovery_watchdog_clear_recovery_flag();
      }
      s_boot_mode = BOOT_MODE_HEADLESS;

      /* Turn off backlight to ensure it doesn't stay stuck on */
      ESP_LOGI(TAG, "Turning off LCD backlight (GPIO %d)", LCD_BACKLIGHT_PIN);
      gpio_config_t io_conf = {
          .pin_bit_mask = (1ULL << LCD_BACKLIGHT_PIN),
          .mode = GPIO_MODE_OUTPUT,
          .pull_up_en = GPIO_PULLUP_DISABLE,
          .pull_down_en = GPIO_PULLDOWN_DISABLE,
          .intr_type = GPIO_INTR_DISABLE,
      };
      gpio_config(&io_conf);
      gpio_set_level((gpio_num_t)LCD_BACKLIGHT_PIN, 0);

      /* Start connectivity watchdog since we are now headless */
      recovery_watchdog_start_wifi_monitor();

    } else {
      /* Delay to ensure LCD memory allocation completes (LCD init takes ~600ms)
       */
      vTaskDelay(pdMS_TO_TICKS(2000));

      /* In recovery mode, clear the flag now that we have LCD up */
      if (s_boot_mode == BOOT_MODE_RECOVERY) {
        recovery_watchdog_clear_recovery_flag();
        ESP_LOGI(TAG, "Recovery flag cleared - LCD initialized successfully");
      }
    }
  } else {
    ESP_LOGI(TAG, "Skipping LCD initialization (headless mode)");

    /* Explicitly turn off the backlight hardware to ensure display is OFF.
     * In headless mode, the LCD task is not started, but the backlight GPIO
     * may default to ON depending on the board's pull resistors.
     * We configure the pin as a simple GPIO output and drive it LOW.
     */
    ESP_LOGI(TAG, "Turning off LCD backlight (GPIO %d) for headless mode",
             LCD_BACKLIGHT_PIN);
    gpio_config_t io_conf = {
        .pin_bit_mask = (1ULL << LCD_BACKLIGHT_PIN),
        .mode = GPIO_MODE_OUTPUT,
        .pull_up_en = GPIO_PULLUP_DISABLE,
        .pull_down_en = GPIO_PULLDOWN_DISABLE,
        .intr_type = GPIO_INTR_DISABLE,
    };
    gpio_config(&io_conf);
    gpio_set_level((gpio_num_t)LCD_BACKLIGHT_PIN, 0);

    /* In headless mode, start the connectivity watchdog monitoring */
    recovery_watchdog_start_wifi_monitor();
  }

  /* Start WiFi Management Task */
  if (wifi_task_start() != ESP_OK) {
    ESP_LOGE(TAG, "Failed to start WiFi task");
    return;
  }

  /* Start System Monitoring Task */
  if (system_task_start() != ESP_OK) {
    ESP_LOGE(TAG, "Failed to start system task");
    return;
  }

  /* Start AWS IoT Task */
  if (aws_iot_task_start() != ESP_OK) {
    ESP_LOGE(TAG, "Failed to start AWS IoT task");
    return;
  }

  /* Start InfluxDB Task - DISABLED (Data now routed via AWS IoT) */
  // if (influxdb_task_st

